import { CommonModule } from '@angular/common';
import { Component, ElementRef, HostListener, inject } from '@angular/core';
import { FormControl, ReactiveFormsModule } from '@angular/forms';
import { Subject, of } from 'rxjs';
import { debounceTime, delay, distinctUntilChanged, map, startWith, switchMap, tap } from 'rxjs/operators';

@Component({
  selector: 'app-root',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule],
  templateUrl: './app.component.html',
  styleUrls: ['./app.component.css']
})
export class AppComponent {
  private readonly host = inject(ElementRef<HTMLElement>);

  readonly listboxId = 'autocomplete-listbox';

  private readonly cities: string[] = [
    'Amsterdam', 'Ankara', 'Athens', 'Austin',
    'Barcelona', 'Berlin', 'Boston', 'Brussels',
    'Chicago', 'Copenhagen',
    'Dubai',
    'Edinburgh',
    'Frankfurt',
    'Hamburg',
    'Istanbul', 'Izmir',
    'London', 'Los Angeles',
    'Madrid', 'Miami', 'Milan', 'Munich',
    'New York',
    'Oslo',
    'Paris', 'Prague',
    'Rome',
    'San Diego', 'San Francisco', 'San Jose', 'Seattle',
    'Tokyo',
    'Vienna',
    'Zurich'
  ];

  readonly queryControl = new FormControl<string>('');

  isOpen = false;
  activeIndex = -1;

  private readonly searchTerm$ = new Subject<string>();

  readonly results$ = this.searchTerm$.pipe(
    startWith(this.queryControl.value ?? ''),
    map((v: string) => String(v ?? '').trim()),
    debounceTime(300),
    distinctUntilChanged(),
    tap((q: string) => {
      if (!q) {
        this.isOpen = false;
        this.activeIndex = -1;
      } else {
        this.isOpen = true;
        this.activeIndex = -1;
      }
    }),
    switchMap((q: string) => (q ? this.search(q) : of([] as string[])))
  );

  onInput(value: string): void {
    this.queryControl.setValue(value);
    this.searchTerm$.next(value);
  }

  onFocus(): void {
    const q = String(this.queryControl.value ?? '').trim();
    if (q) this.isOpen = true;
  }

  onKeyDown(ev: KeyboardEvent): void {
    if (ev.key === 'Escape') {
      this.isOpen = false;
      this.activeIndex = -1;
      return;
    }

    if (!this.isOpen && (ev.key === 'ArrowDown' || ev.key === 'ArrowUp')) {
      const q = String(this.queryControl.value ?? '').trim();
      this.isOpen = !!q;
    }

    const options = this.host.nativeElement.querySelectorAll('[role="option"]');
    const len = options.length;
    if (!this.isOpen || len === 0) return;

    if (ev.key === 'ArrowDown') {
      ev.preventDefault();
      this.activeIndex = this.activeIndex < 0 ? 0 : (this.activeIndex + 1) % len;
      return;
    }

    if (ev.key === 'ArrowUp') {
      ev.preventDefault();
      this.activeIndex = this.activeIndex < 0 ? len - 1 : (this.activeIndex - 1 + len) % len;
      return;
    }

    if (ev.key === 'Enter') {
      if (this.activeIndex >= 0 && this.activeIndex < len) {
        ev.preventDefault();
        const el = options[this.activeIndex] as HTMLElement;
        const text = el.textContent ?? '';
        this.select(text);
      }
      return;
    }
  }

  select(value: string): void {
    this.queryControl.setValue(value);
    this.isOpen = false;
    this.activeIndex = -1;
    this.searchTerm$.next(value);
  }


  optionId(i: number): string {
    return `opt-${i}`;
  }

  highlight(item: string, queryRaw: unknown): string {
    const q = String(queryRaw ?? '').trim();
    if (!q) return this.escapeHtml(item);

    const idx = item.toLowerCase().indexOf(q.toLowerCase());
    if (idx < 0) return this.escapeHtml(item);

    const before = this.escapeHtml(item.slice(0, idx));
    const mid = this.escapeHtml(item.slice(idx, idx + q.length));
    const after = this.escapeHtml(item.slice(idx + q.length));
    return `${before}<mark>${mid}</mark>${after}`;
  }

  @HostListener('document:mousedown', ['$event'])
  onDocMouseDown(ev: MouseEvent): void {
    const target = ev.target as Node | null;
    if (!target) return;
    if (!this.host.nativeElement.contains(target)) {
      this.isOpen = false;
      this.activeIndex = -1;
    }
  }

  private search(q: string) {
    const needle = q.toLowerCase();
    const filtered = this.cities
      .filter(c => c.toLowerCase().includes(needle))
      .slice(0, 8);

    return of(filtered).pipe(delay(150));
  }

  private escapeHtml(s: string): string {
    return s
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/\"/g, '&quot;')
      .replace(/'/g, '&#39;');
  }
}
